-- ========================================================-- PDI智能监测平台 - 数据初始化脚本 (PostgreSQL)-- Phase 1: 基础设施层初始化数据-- ========================================================-- 初始化站点数据INSERT INTO site (id, name, code, site_id, created_at, updated_at, deleted_at, created_by) VALUES (1, '金桥库', 'JQ', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, NULL, NULL), (2, '凯迪库', 'KD', 2, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, NULL, NULL) ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, code = EXCLUDED.code, updated_at = CURRENT_TIMESTAMP;-- 重置序列以确保后续插入从正确ID开始SELECT setval('site_id_seq', 2, true);-- 初始化系统角色数据INSERT INTO sys_role (id, name, code, description, site_id, created_at, updated_at, deleted_at, created_by) VALUES (1, '系统管理员', 'ROLE_ADMIN', '系统超级管理员，拥有所有权限', 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, NULL, NULL), (2, '站点管理员', 'ROLE_SITE_ADMIN', '站点级管理员，管理单个站点的所有资源', 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, NULL, NULL), (3, '操作员', 'ROLE_OPERATOR', '普通操作员，可查看数据和处理告警', 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, NULL, NULL), (4, '观察员', 'ROLE_VIEWER', '只读权限，仅可查看数据', 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, NULL, NULL) ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, updated_at = CURRENT_TIMESTAMP;-- 重置序列SELECT setval('sys_role_id_seq', 4, true);